// test/unit/core/AnnotationLoader.unit.test.js

const assert = require('assert');
const path = require('path');
const fs = require('fs');
const AnnotationLoader = require('../../../src/core/AnnotationLoader');
const AnnotationRegistry = require('../../../src/core/AnnotationRegistry');

/**
 * Unit-Test für AnnotationLoader.
 * Testet das Laden von Annotationen und Prozessoren aus dem lib-Verzeichnis.
 */
describe('AnnotationLoader (Unit)', () => {
  const annotationDir = path.join(__dirname, '../../../src/lib/annotations/bean');
  const processorDir = path.join(__dirname, '../../../src/lib/processors/bean');
  const annotationFile = path.join(annotationDir, 'TestAnnotation.js');
  const processorFile = path.join(processorDir, 'TestAnnotationProcessor.js');

  before(() => {
    // Stelle sicher, dass die Testverzeichnisse existieren
    fs.mkdirSync(annotationDir, { recursive: true });
    fs.mkdirSync(processorDir, { recursive: true });

    // Dummy Annotation
    fs.writeFileSync(annotationFile, `
      class TestAnnotation {
        constructor(params) {
          this.name = params.name;
        }
      }
      module.exports = TestAnnotation;
    `);

    // Dummy Processor
    fs.writeFileSync(processorFile, `
      class TestAnnotationProcessor {
        process(annotation, target) {
          target.processed = true;
        }
      }
      module.exports = TestAnnotationProcessor;
    `);
  });

  it('should load and register annotation and processor', () => {
    AnnotationLoader.load();

    const annotation = AnnotationRegistry.getAnnotation('TestAnnotation');
    const processor = AnnotationRegistry.getProcessor('TestAnnotation');

    assert.ok(annotation, 'Annotation should be registered');
    assert.ok(processor, 'Processor should be registered');
    assert.strictEqual(typeof annotation, 'function');
    assert.strictEqual(typeof processor, 'function');
  });

  after(() => {
    // Clean up test files
    fs.unlinkSync(annotationFile);
    fs.unlinkSync(processorFile);
  });
});